import React from 'react';
import './Banner.css';

export const Banner = () => {
  return (
    <div className="banner" id="inicio">
      <div className="banner-content">
        <h1>La mejor tecnología a tu alcance</h1>
        <p>Encuentra laptops, smartphones y accesorios con los mejores precios.</p>
        <button className="btn-comprar">Ver Productos</button>
      </div>
    </div>
  );
};
